1	// claim-office.ts
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  Sword: 100,
5	  Amulet: 60,
6	  Staff: 80,
7	  Potion: 40,
8	  Rune: 25,
9	  Moonstone: 25,
10	};
11	
12	const INSURANCE_VALUES: Record<string, number> = {
13	  Sword: 1000,
14	  Amulet: 600,
15	  Staff: 800,
16	  Potion: 400,
17	  Rune: 250,
18	  Moonstone: 250,
19	};
20	
21	const FIRST_INSURANCE_PERCENT = 110;
22	const PROCESSING_FEE = 5;
23	const DEDUCTIBLE_PER_DAMAGE = 100;
24	const CAP_MULTIPLIER = 2;
25	
26	type Item = { type: string; cursed?: boolean; enchantment?: number };
27	type Customer = { name: string; years: number; contracts: number };
28	
29	const LOYALTY_YEARS_THRESHOLD = 2;
30	const LOYALTY_DISCOUNT_RATE = 0.2;
31	
32	const COMPONENT_TYPES = new Set(["Rune", "Moonstone"]);
33	const BLOCK_OF_3_BASE_PREMIUM = 60;
34	const BLOCK_OF_3_SIZE = 3;
35	const CURSED_SURCHARGE_RATE = 0.5;
36	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
37	const HIGH_ENCHANTMENT_THRESHOLD = 5;
38	const HIGH_ENCH_CLAIM_THRESHOLD = 8;
39	const HIGH_ENCH_CLAIM_RATE = 0.5;
40	
41	const isBlockOf3Components = (type: string, count: number): boolean =>
42	  COMPONENT_TYPES.has(type) && count === BLOCK_OF_3_SIZE;
43	
44	const baseForGroup = (type: string, count: number): number =>
45	  isBlockOf3Components(type, count)
46	    ? BLOCK_OF_3_BASE_PREMIUM
47	    : BASE_PREMIUMS[type] * count;
48	
49	const countItemsByType = (items: Item[]): Record<string, number> =>
50	  items.reduce<Record<string, number>>((counts, item) => {
51	    counts[item.type] = (counts[item.type] ?? 0) + 1;
52	    return counts;
53	  }, {});
54	
55	const baseTotalFor = (items: Item[]): number =>
56	  Object.entries(countItemsByType(items))
57	    .reduce((total, [type, count]) => total + baseForGroup(type, count), 0);
58	
59	const surchargeOnBase = (item: Item, applies: boolean, rate: number): number =>
60	  applies ? BASE_PREMIUMS[item.type] * rate : 0;
61	
62	const cursedSurchargeFor = (item: Item): number =>
63	  surchargeOnBase(item, item.cursed === true, CURSED_SURCHARGE_RATE);
64	
65	const highEnchantmentSurchargeFor = (item: Item): number =>
66	  surchargeOnBase(item, (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, HIGH_ENCHANTMENT_SURCHARGE_RATE);
67	
68	const itemSurchargesFor = (items: Item[]): number =>
69	  items.reduce((total, item) => total + cursedSurchargeFor(item) + highEnchantmentSurchargeFor(item), 0);
70	
71	const loyaltyDiscountFor = (customer: Customer, baseTotal: number): number =>
72	  customer.years >= LOYALTY_YEARS_THRESHOLD ? baseTotal * LOYALTY_DISCOUNT_RATE : 0;
73	
74	const applyFirstInsurance = (baseTotal: number): number =>
75	  (baseTotal * FIRST_INSURANCE_PERCENT) / 100;
76	
77	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
78	
79	const followUpDiscountFor = (isFollowUp: boolean, baseTotal: number): number =>
80	  isFollowUp ? baseTotal * FOLLOW_UP_DISCOUNT_RATE : 0;
81	
82	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
83	  const baseTotal = baseTotalFor(items);
84	  const policyBase = applyFirstInsurance(baseTotal);
85	  const itemSurcharges = itemSurchargesFor(items);
86	  const loyaltyDiscount = loyaltyDiscountFor(customer, baseTotal);
87	  const followUpDiscount = followUpDiscountFor(isFollowUp, baseTotal);
88	  return Math.ceil(policyBase + itemSurcharges - loyaltyDiscount - followUpDiscount + PROCESSING_FEE);
89	};
90	
91	type Policy = { items: Item[]; cap: number; remainingCap: number };
92	type Damage = { itemType: string; amount: number };
93	type ClaimStep = { type: "claim"; policy: number; incident: { damages: Damage[] } };
94	type QuoteStep = { type: "quote"; items: Item[] };
95	type Step = QuoteStep | ClaimStep;
96	type Scenario = { customer: Customer; steps: Step[] };
97	type ClaimResult = { payout: number; remainingCap: number };
98	type QuoteResult = { premium: number };
99	
100	const insuranceSumFor = (items: Item[]): number =>
101	  items.reduce((sum, item) => sum + INSURANCE_VALUES[item.type], 0);
102	
103	const payoutForDamage = (damage: Damage, items: Item[]): number => {
104	  const item = items.find((i) => i.type === damage.itemType);
105	  const reimbursable = (item?.enchantment ?? 0) >= HIGH_ENCH_CLAIM_THRESHOLD
106	    ? damage.amount * HIGH_ENCH_CLAIM_RATE
107	    : damage.amount;
108	  return Math.max(0, reimbursable - DEDUCTIBLE_PER_DAMAGE);
109	};
110	
111	const totalPayoutFor = (damages: Damage[], items: Item[]): number =>
112	  Math.floor(damages.reduce((total, damage) => total + payoutForDamage(damage, items), 0));
113	
114	const clampToCap = (amount: number, remainingCap: number): number =>
115	  Math.min(amount, remainingCap);
116	
117	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
118	  const policy = policies[step.policy];
119	  const payout = clampToCap(totalPayoutFor(step.incident.damages, policy.items), policy.remainingCap);
120	  policy.remainingCap -= payout;
121	  return { payout, remainingCap: policy.remainingCap };
122	};
123	
124	const newPolicyFor = (items: Item[]): Policy => {
125	  const cap = CAP_MULTIPLIER * insuranceSumFor(items);
126	  return { items, cap, remainingCap: cap };
127	};
128	
129	const processQuote = (step: QuoteStep, customer: Customer, isFollowUp: boolean, policies: Policy[]): QuoteResult => {
130	  policies.push(newPolicyFor(step.items));
131	  return { premium: quotePremium(step.items, customer, isFollowUp) };
132	};
133	
134	export function processScenario(scenario: any): unknown {
135	  const policies: Policy[] = [];
136	  const results = (scenario.steps as Step[]).map((step, index) =>
137	    step.type === "claim"
138	      ? processClaim(step, policies)
139	      : processQuote(step, scenario.customer, index > 0, policies),
140	  );
141	  return { results };
142	}
